#include <stdio.h>
#include "board.h"
#include "gpio.h"

#define LED_PIN  GPIO_PIN_13
#define DELAY_MS  500

int main(void) {
    board_init();
    gpio_init(LED_PIN, GPIO_MODE_OUTPUT);

    printf("LED Blink Demo Started!\n");

    while (1) {
        gpio_toggle(LED_PIN);
        delay_ms(DELAY_MS);
    }

    return 0;
}
